# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from flask_graphql import GraphQLView
import graphene

# Define your data models here
class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    category = graphene.Field(lambda: Category)
    reviews = graphene.List(lambda: Review)

class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()

class Review(graphene.ObjectType):
    id = graphene.ID()
    content = graphene.String()
    product = graphene.Field(lambda: Product)

# Define your data source
products_data = [
    {"id": "1", "name": "Laptop", "category_id": "1"},
    {"id": "2", "name": "Smartphone", "category_id": "2"}
]

categories_data = [
    {"id": "1", "name": "Electronics"},
    {"id": "2", "name": "Mobile Phones"}
]

reviews_data = [
    {"id": "1", "content": "Great product!", "product_id": "1"},
    {"id": "2", "content": "Excellent phone.", "product_id": "2"}
]

# Define the resolvers
def resolve_product(_, info, id):
    return next((p for p in products_data if p['id'] == id), None)

def resolve_category(_, info, id):
    return next((c for c in categories_data if c['id'] == id), None)

def resolve_review(_, info, id):
    return next((r for r in reviews_data if r['id'] == id), None)

# Define the queries
class Query(graphene.ObjectType):
    product = graphene.Field(Product, id=graphene.ID(required=True))
    category = graphene.Field(Category, id=graphene.ID(required=True))
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_product(self, info, id):
        return resolve_product(_, info, id)

    def resolve_category(self, info, id):
        return resolve_category(_, info, id)

    def resolve_review(self, info, id):
        return resolve_review(_, info, id)

# Create the schema
schema = graphene.Schema(query=Query)

# Set up Flask app with GraphQLView
app = Flask(__name__)
app.add_url_rule('/graphql', view_func=GraphQLView.as_view(
    'graphql',
    schema=schema,
    graphiql=True  # Enable GraphiQL for testing
))

if __name__ == '__main__':
    app.run(debug=True)